// TC Briefing → Discord embed builder
// Input: webhook body with briefing items from Trading Coordinator
//
// Expected input shape:
// {
//   briefing: [
//     {
//       symbol: "SK하이닉스",
//       action: "sell",       // sell | buy | hold | add_buy
//       confidence: 85,
//       reasons: ["목표가 도달", "거래량 감소"],
//       paperclip_issue_url: "http://..."
//     }
//   ],
//   generated_at: "2026-04-16T09:00:00Z",
//   title: "TC 브리핑"  // optional
// }

const botToken = ($env.DISCORD_TC_BRIEFING_BOT_TOKEN || '').trim();
const channelId = ($env.DISCORD_TC_BRIEFING_CHANNEL_ID || '').trim();

if (!botToken || !channelId) {
  return [{
    json: {
      shouldSend: false,
      reason: !botToken
        ? 'DISCORD_TC_BRIEFING_BOT_TOKEN not configured'
        : 'DISCORD_TC_BRIEFING_CHANNEL_ID not configured',
    }
  }];
}

const input = $input.first().json;
const body = input.body || input;
const briefing = Array.isArray(body.briefing) ? body.briefing : [];
const title = body.title || 'TC 브리핑';
const generatedAt = body.generated_at || new Date().toISOString();

if (briefing.length === 0) {
  return [{
    json: {
      shouldSend: false,
      reason: 'briefing array is empty',
    }
  }];
}

// Category config
const categories = {
  sell:    { label: '매도', emoji: '🔴', color: 0xE74C3C },
  buy:     { label: '매수', emoji: '🟢', color: 0x2ECC71 },
  hold:    { label: '홀드', emoji: '🟡', color: 0xF1C40F },
  add_buy: { label: '추가매수', emoji: '🔵', color: 0x3498DB },
};

// Group items by action
const grouped = {};
for (const item of briefing) {
  const action = String(item.action || 'hold').toLowerCase();
  if (!grouped[action]) grouped[action] = [];
  grouped[action].push(item);
}

// Build embeds (one per category)
const embeds = [];
const categoryOrder = ['sell', 'buy', 'add_buy', 'hold'];

for (const action of categoryOrder) {
  const items = grouped[action];
  if (!items || items.length === 0) continue;
  const cat = categories[action] || categories.hold;

  const fields = items.map(item => {
    const confidence = item.confidence != null ? ` (${item.confidence}%)` : '';
    const reasons = Array.isArray(item.reasons)
      ? item.reasons.slice(0, 3).join(' / ')
      : '';
    const link = item.paperclip_issue_url
      ? `\n[Paperclip에서 결정하기](${item.paperclip_issue_url})`
      : '';

    return {
      name: `${cat.emoji} ${item.symbol || 'Unknown'}${confidence}`,
      value: (reasons || '근거 없음') + link,
      inline: false,
    };
  });

  embeds.push({
    title: `${cat.emoji} ${cat.label} (${items.length}건)`,
    color: cat.color,
    fields: fields.slice(0, 25),
  });
}

// Discord allows max 10 embeds per message
const embedsToSend = embeds.slice(0, 10);

// Add footer to last embed
if (embedsToSend.length > 0) {
  embedsToSend[embedsToSend.length - 1].footer = {
    text: `${title} · ${new Date(generatedAt).toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' })}`,
  };
  embedsToSend[embedsToSend.length - 1].timestamp = generatedAt;
}

return [{
  json: {
    shouldSend: true,
    channelId,
    botToken,
    payload: {
      embeds: embedsToSend,
    },
  }
}];
